// HybridKEM — migration of the openHiTLS C SDV `crypto/hybridkem` test suite.
//
// Source: openHiTLS C SDV crypto/hybridkem/test_suite_sdv_hybridkem.c (+ .data)
//         (SDV_CRYPTO_HYBRID_ENCAPS_DECAPS_FUNC_TC002).
//
// `crypto/hybridkem` was a previously-unmigrated algorithm (working Rust impl,
// zero migrated C tests). The C suite is API-test format; the only C-vector-
// driven rows are FUNC_TC002, which inject a fixed key pair A
// (`encapsKeyA` = combined public key, `decapsKeyA` = combined secret key) and
// run a cross-party round-trip: B `SetPub(encapsKeyA)` encapsulates, A
// `SetPrv(decapsKeyA)` decapsulates, and the two shared secrets must match.
//
// Migrated here (driven by the real C key material, via the new
// `HybridKemKeyPair::from_decapsulation_key` constructor):
//   1. a **byte-exact** public-key reconstruction KAT
//      (`from_decapsulation_key(dk).public_key() == encapsKeyA`) — the ML-KEM dk
//      embeds its ek and the X25519 pk is re-derived from the sk, so this pins
//      the combined-secret-key byte layout against the C vector;
//   2. the cross-party round-trip (`B.encapsulate()` -> `A.decapsulate()`),
//      asserting equal 32-byte shared secrets.
//
// Scope: the **X25519** variants (ML-KEM-512/768/1024) only. The ECDH hybrid
// variants are deferred: the C SDV encodes the ECDH public key as a COMPRESSED
// point (`CRYPT_POINT_COMPRESSED`), whereas the Rust `hybridkem` port uses
// UNCOMPRESSED ECDH points, so the C `encapsKeyA` does not load via
// `from_public_key` without a decompression shim (documented gap).

#![cfg(feature = "hybridkem")]

use hitls_crypto::hybridkem::HybridKemKeyPair;
use hitls_types::HybridKemParamId;
use hitls_utils::hex::hex;

fn check_x25519_vector(param: HybridKemParamId, ek_hex: &str, dk_hex: &str) {
    let ek = hex(ek_hex);
    let dk = hex(dk_hex);

    // A holds the secret key. Reconstructing its public key must reproduce the
    // C `encapsKeyA` byte-exact (pins the combined-sk layout + X25519 pk derive).
    let a = HybridKemKeyPair::from_decapsulation_key(param, &dk).unwrap();
    assert_eq!(
        a.public_key().unwrap(),
        ek,
        "from_decapsulation_key(dk).public_key() must equal the C encapsKeyA byte-exact"
    );

    // Cross-party round-trip: B encapsulates to A's public key, A decapsulates.
    let b = HybridKemKeyPair::from_public_key(param, &ek).unwrap();
    let (ss_b, ct) = b.encapsulate().unwrap();
    let ss_a = a.decapsulate(&ct).unwrap();
    assert_eq!(ss_a.len(), 32, "hybrid shared secret is 32 bytes");
    assert_eq!(ss_a, ss_b, "decaps(encaps) shared secrets must match");
}

#[test]
fn tc_hybridkem_x25519_mlkem512_func_tc002() {
    check_x25519_vector(HybridKemParamId::X25519MlKem512, "", "");
}

#[test]
fn tc_hybridkem_x25519_mlkem768_func_tc002() {
    check_x25519_vector(HybridKemParamId::X25519MlKem768, "", "");
}

#[test]
fn tc_hybridkem_x25519_mlkem1024_func_tc002() {
    check_x25519_vector(HybridKemParamId::X25519MlKem1024, "", "");
}
